#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 1000000

int minOperations(char *A, char *B) {
    int n = strlen(A);
    int queueSize = 0;
    char **queue = (char **)malloc(2 * n * sizeof(char *));
    for (int i = 0; i < 2 * n; i++) {
        queue[i] = (char *)malloc((n + 1) * sizeof(char));
    }
    strcpy(queue[queueSize++], A);
    int *dist = (int *)malloc(2 * n * sizeof(int));
    for (int i = 0; i < 2 * n; i++) {
        dist[i] = -1;
    }
    dist[0] = 0;
    while (queueSize > 0) {
        char *curr = queue[queueSize - 1];
        queueSize--;
        if (strcmp(curr, B) == 0) {
            return dist[queueSize];
        }
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                char *next = (char *)malloc((n + 1) * sizeof(char));
                strcpy(next, curr);
                next[i] = (next[i] & next[j]) + '0';
                next[j] = (next[i] & next[j]) + '0';
                int found = 0;
                for (int k = 0; k < queueSize; k++) {
                    if (strcmp(queue[k], next) == 0) {
                        found = 1;
                        break;
                    }
                }
                if (!found) {
                    queue[queueSize] = next;
                    dist[queueSize] = dist[queueSize - 1] + 1;
                    queueSize++;
                }
            }
        }
    }
    return -1;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T-- > 0) {
        char A[MAX], B[MAX];
        scanf("%s %s", A, B);
        int minOps = minOperations(A, B);
        if (minOps == -1) {
            printf("Unlucky Chef\n");
        } else {
            printf("Lucky Chef\n%d\n", minOps);
        }
    }
    return 0;
}

