#include <iostream>
#include <queue>
#include <string>
#include <unordered_set>
using namespace std;

int minOperations(string A, string B) {
    int n = A.size();
    queue<string> q;
    q.push(A);
    unordered_set<string> visited;
    visited.insert(A);
    int dist = 0;
    while (!q.empty()) {
        int size = q.size();
        for (int i = 0; i < size; i++) {
            string curr = q.front();
            q.pop();
            if (curr == B) {
                return dist;
            }
            for (int j = 0; j < n; j++) {
                for (int k = j + 1; k < n; k++) {
                    string next = curr;
                    next[j] = (next[j] & next[k]) + '0';
                    next[k] = (next[j] & next[k]) + '0';
                    if (visited.find(next) == visited.end()) {
                        q.push(next);
                        visited.insert(next);
                    }
                }
            }
        }
        dist++;
    }
    return -1;
}

int main() {
    int T;
    cin >> T;
    while (T-- > 0) {
        string A, B;
        cin >> A >> B;
        int minOps = minOperations(A, B);
        if (minOps == -1) {
            cout << "Unlucky Chef" << endl;
        } else {
            cout << "Lucky Chef" << endl << minOps << endl;
        }
    }
    return 0;
}

