import java.util.Queue;
import java.util.LinkedList;
import java.util.HashSet;
import java.util.Scanner;

public class Main {
    public static int minOperations(String A, String B) {
        int n = A.length();
        Queue<String> q = new LinkedList<>();
        q.add(A);
        HashSet<String> visited = new HashSet<>();
        visited.add(A);
        int dist = 0;
        while (!q.isEmpty()) {
            int size = q.size();
            for (int i = 0; i < size; i++) {
                String curr = q.poll();
                if (curr.equals(B)) {
                    return dist;
                }
                for (int j = 0; j < n; j++) {
                    for (int k = j + 1; k < n; k++) {
                        String next = curr;
                        next = next.substring(0, j) + (char)(next.charAt(j) & next.charAt(k)) + next.substring(j + 1);
                        next = next.substring(0, k) + (char)(next.charAt(j) & next.charAt(k)) + next.substring(k + 1);
                        if (!visited.contains(next)) {
                            q.add(next);
                            visited.add(next);
                        }
                    }
                }
            }
            dist++;
        }
        return -1;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String A = sc.next();
            String B = sc.next();
            int minOps = minOperations(A, B);
            if (minOps == -1) {
                System.out.println("Unlucky Chef");
            } else {
                System.out.println("Lucky Chef");
                System.out.println(minOps);
            }
        }
    }
}

