    q = deque([A])
    visited = {A}
    dist = 0
    while q:
        size = len(q)
        for _ in range(size):
            curr = q.popleft()
            if curr == B:
                return dist
            for j in range(n):
                for k in range(j + 1, n):
                    next = list(curr)
                    next[j] = str(int(next[j]) & int(next[k]))
                    next[k] = str(int(next[j]) & int(next[k]))
                    next = ''.join(next)
                    if next not in visited:
                        q.append(next)
                        visited.add(next)
        dist += 1
    return -1

